 35	import styles from '@patternfly/react-topology/src/css/topology-components';
 36	import * as React from 'react';
 37	import { hoverEvent } from '../topology-content';
 38	
 39	const StatusQuadrant = TopologyQuadrant.upperLeft;
 40	
 41	const getStatusIcon = (status: NodeStatus) => {
 42	  switch (status) {
 43	    case NodeStatus.danger:
 44	      return <ExclamationCircleIcon className="pf-m-danger" />;
 45	    case NodeStatus.warning:
 46	      return <ExclamationTriangleIcon className="pf-m-warning" />;
