156	const DefaultNodeInner: React.FunctionComponent<DefaultNodeInnerProps> = observer(
157	  ({
158	    className,
159	    element,
160	    selected,
161	    hover,
162	    scaleNode,
163	    showLabel = true,
164	    label,
165	    secondaryLabel,
166	    labelClassName,
167	    labelPosition,
168	    scaleLabel,
169	    truncateLength,
170	    labelIconClass,
171	    labelIcon,
172	    labelIconPadding,
173	    nodeStatus,
174	    showStatusBackground,
175	    showStatusDecorator = false,
176	    statusDecoratorTooltip,
177	    getCustomShape,
178	    getShapeDecoratorCenter,
179	    onStatusDecoratorClick,
180	    badge,
181	    badgeColor,
182	    badgeTextColor,
183	    badgeBorderColor,
184	    badgeClassName,
185	    badgeLocation,
186	    onSelect,
187	    children,
188	    attachments,
189	    dragNodeRef,
190	    dragging,
191	    edgeDragging,
192	    canDrop,
193	    dropTarget,
194	    dndDropRef,
195	    onHideCreateConnector,
196	    onShowCreateConnector,
197	    onContextMenu,
198	    contextMenuOpen,
199	    shadowed,
200	    filtered,
201	    highlighted,
202	    isDark
203	  }) => {
204	    const [hovered, hoverRef] = useHover();
205	    const status = nodeStatus || element.getNodeStatus();
206	    const refs = useCombineRefs<SVGEllipseElement>(
207	      hoverRef as React.Ref<SVGEllipseElement>,
208	      dragNodeRef as React.Ref<SVGEllipseElement>
209	    );
210	    const { width, height } = element.getDimensions();
211	    const isHover = hover !== undefined ? hover : hovered;
212	    const [nodeScale, setNodeScale] = React.useState<number>(1);
213	    const decoratorRef = React.useRef();
214	
215	    const statusDecorator = React.useMemo(() => {
216	      if (!status || !showStatusDecorator) {
217	        return null;
218	      }
219	
220	      const icon = getStatusIcon(status);
221	      if (!icon) {
222	        return null;
223	      }
224	
225	      const { x, y } = getShapeDecoratorCenter
226	        ? getShapeDecoratorCenter(StatusQuadrant, element)
227	        : getDefaultShapeDecoratorCenter(StatusQuadrant, element);
228	
229	      const decorator = (
230	        <Decorator
231	          x={x}
232	          y={y}
233	          radius={decoratorRadius}
234	          showBackground
235	          onClick={e => onStatusDecoratorClick && onStatusDecoratorClick(e, element)}
236	          icon={<g className={css(styles.topologyNodeDecoratorStatus)}>{icon}</g>}
237	          ariaLabel={status}
238	          innerRef={decoratorRef as unknown as React.Ref<SVGGElement> | undefined}
239	        />
240	      );
241	
242	      if (statusDecoratorTooltip) {
243	        return (
244	          <Tooltip triggerRef={decoratorRef} content={statusDecoratorTooltip} position={TooltipPosition.left}>
245	            {decorator}
246	          </Tooltip>
247	        );
248	      }
249	
250	      return decorator;
251	    }, [status, showStatusDecorator, getShapeDecoratorCenter, element, statusDecoratorTooltip, onStatusDecoratorClick]);
252	
253	    React.useEffect(() => {
254	      if (isHover) {
255	        if (onShowCreateConnector) {
256	          onShowCreateConnector();
257	        }
258	      } else {
259	        if (onHideCreateConnector) {
260	          onHideCreateConnector();
261	        }
262	      }
263	      if (element.hasController()) {
264	        element.getController().fireEvent(hoverEvent, {
265	          ...element.getData(),
266	          id: element.getId(),
267	          isHovered: isHover
268	        });
269	      }
270	    }, [isHover, onShowCreateConnector, onHideCreateConnector, element]);
271	
272	    const ShapeComponent = (getCustomShape && getCustomShape(element)) || getShapeComponent(element);
273	
274	    const groupClassName = css(
275	      styles.topologyNode,
276	      className,
277	      isHover && 'pf-m-hover',
278	      (dragging || edgeDragging) && 'pf-m-dragging',
279	      canDrop && 'pf-m-highlight',
280	      canDrop && dropTarget && 'pf-m-drop-target',
281	      selected && 'pf-m-selected',
282	      StatusModifier[status],
283	      'topology',
284	      shadowed && 'shadowed',
285	      filtered && 'node-filtered',
286	      highlighted && 'node-highlighted',
287	      isDark && 'dark'
288	    );
289	
290	    const backgroundClassName = css(
291	      styles.topologyNodeBackground,
292	      showStatusBackground && StatusModifier[status],
293	      showStatusBackground && selected && 'pf-m-selected'
294	    );
295	
296	    let filter;
297	    if (status === 'danger') {
298	      filter = createSvgIdUrl(nodeShadowFilterIdDanger);
299	    } else if (isHover || dragging || edgeDragging || dropTarget) {
300	      filter = createSvgIdUrl(nodeShadowFilterIdHover);
301	    }
302	
303	    const nodeLabelPosition = labelPosition || element.getLabelPosition();
304	    const scale = element.getGraph().getScale();
305	
306	    const animationRef = React.useRef<number>();
307	    const scaleGoal = React.useRef<number>(1);
308	    const nodeScaled = React.useRef<boolean>(false);
309	
310	    React.useEffect(() => {
311	      if (!scaleNode || scale >= 1) {
312	        setNodeScale(1);
313	        nodeScaled.current = false;
314	        if (animationRef.current) {
315	          cancelAnimationFrame(animationRef.current);
316	          animationRef.current = 0;
317	        }
318	      } else {
319	        scaleGoal.current = 1 / scale;
320	        const scaleDelta = scaleGoal.current - scale;
321	        const initTime = performance.now();
322	
323	        const bumpScale = (bumpTime: number) => {
324	          const scalePercent = (bumpTime - initTime) / scaleUpTime;
325	          const nextScale = Math.min(scale + scaleDelta * scalePercent, scaleGoal.current);
326	          setNodeScale(nextScale);
327	          if (nextScale < scaleGoal.current) {
328	            animationRef.current = requestAnimationFrame(bumpScale);
329	          } else {
330	            nodeScaled.current = true;
331	            animationRef.current = 0;
332	          }
333	        };
334	
335	        if (nodeScaled.current) {
336	          setNodeScale(scaleGoal.current);
337	        } else if (!animationRef.current) {
338	          animationRef.current = requestAnimationFrame(bumpScale);
339	        }
340	      }
341	      return () => {
342	        if (animationRef.current) {
343	          cancelAnimationFrame(animationRef.current);
344	          animationRef.current = 0;
345	        }
346	      };
347	    }, [scale, scaleNode]);
348	
349	    // counter scale label
350	    const counterScale = (scale: number, scaleMin: number, scaleMax: number, valueMin: number, valueMax: number) => {
351	      if (scale >= scaleMax) {
352	        return valueMin;
353	      } else if (scale <= scaleMin) {
354	        return valueMax;
355	      }
356	      return valueMin + (1 - (scale - scaleMin) / (scaleMax - scaleMin)) * (valueMax - valueMin);
357	    };
358	    const labelScale = scaleLabel ? counterScale(scale, 0.35, 0.85, 1, 1.6) : 1;
359	    const labelPositionScale = scaleLabel ? Math.min(1, 1 / labelScale) : 1;
360	
361	    const { translateX, translateY } = React.useMemo(() => {
362	      if (!scaleNode) {
363	        return { translateX: 0, translateY: 0 };
364	      }
365	      const bounds = element.getBounds();
366	      const translateX = bounds.width / 2 - (bounds.width / 2) * nodeScale;
367	      const translateY = bounds.height / 2 - (bounds.height / 2) * nodeScale;
368	
369	      return { translateX, translateY };
370	    }, [element, nodeScale, scaleNode]);
371	
372	    let labelX;
373	    let labelY;
374	    const labelPaddingX = 8;
375	    const labelPaddingY = 4;
376	    if (nodeLabelPosition === LabelPosition.right) {
377	      labelX = (width + labelPaddingX) * labelPositionScale;
378	      labelY = height / 2;
379	    } else if (nodeLabelPosition === LabelPosition.left) {
380	      labelX = 0;
381	      labelY = height / 2 - labelPaddingY;
382	    } else if (nodeLabelPosition === LabelPosition.top) {
383	      labelX = width / 2;
384	      labelY = labelPaddingY + labelPaddingY / 2;
385	    } else {
386	      labelX = (width / 2) * labelPositionScale;
387	      labelY = height + labelPaddingY + labelPaddingY / 2;
388	    }
389	    return (
390	      <g
391	        className={groupClassName}
392	        transform={`${scaleNode ? `translate(${translateX}, ${translateY})` : ''} scale(${nodeScale})`}
393	      >
394	        <NodeShadows />
395	        <g ref={refs} onClick={onSelect} onContextMenu={onContextMenu}>
396	          {ShapeComponent && (
397	            <ShapeComponent
398	              className={backgroundClassName}
399	              element={element}
400	              width={width}
401	              height={height}
402	              dndDropRef={dndDropRef}
403	              filter={filter}
404	            />
405	          )}
406	          {showLabel && (label || element.getLabel()) && (
407	            <Layer id={isHover ? topLayer : undefined}>
408	              <g
409	                className={groupClassName}
410	                transform={
411	                  isHover
412	                    ? `${scaleNode ? `translate(${translateX}, ${translateY})` : ''} scale(${nodeScale})`
413	                    : undefined
414	                }
415	              >
416	                <g transform={`scale(${labelScale})`}>
417	                  <NodeLabel
418	                    className={css(styles.topologyNodeLabel, labelClassName)}
419	                    x={labelX}
420	                    y={labelY * labelPositionScale}
421	                    position={nodeLabelPosition}
422	                    paddingX={8}
423	                    paddingY={4}
424	                    secondaryLabel={secondaryLabel}
425	                    truncateLength={truncateLength}
426	                    status={status}
427	                    badge={badge}
428	                    badgeColor={badgeColor}
429	                    badgeTextColor={badgeTextColor}
430	                    badgeBorderColor={badgeBorderColor}
431	                    badgeClassName={badgeClassName}
432	                    badgeLocation={badgeLocation}
433	                    onContextMenu={onContextMenu}
434	                    contextMenuOpen={contextMenuOpen}
435	                    hover={isHover}
436	                    labelIconClass={labelIconClass}
437	                    labelIcon={labelIcon}
438	                    labelIconPadding={labelIconPadding}
439	                  >
440	                    {label || element.getLabel()}
441	                  </NodeLabel>
442	                </g>
443	              </g>
444	            </Layer>
445	          )}
446	          {children}
447	        </g>
448	        {statusDecorator}
449	        {attachments}
450	      </g>
451	    );
452	  }
453	);
454	
455	const DefaultNode: React.FunctionComponent<DefaultNodeProps> = ({
456	  element,
457	  showLabel = true,
458	  showStatusDecorator = false,
459	  ...rest
460	}: DefaultNodeProps) => {
461	  if (!isNode(element)) {
462	    throw new Error('DefaultNode must be used only on Node elements');
463	  }
464	  return (
465	    <DefaultNodeInner
466	      element={element as Node}
467	      showLabel={showLabel}
468	      showStatusDecorator={showStatusDecorator}
469	      {...rest}
470	    />
471	  );
472	};
473	
474	export default DefaultNode;
